VALUES
  ('social-worker-moex-05620', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '處理兒童的暴力或攻擊行為的描述，下列那一項敘述錯誤？', '["若行為不會造成傷害或危險，可以採用不相容的反應技巧，故意不理會兒童的攻擊行為", "可以運用暫停的方法，將孩子移開爭執的場所，提供他恢復情緒控制的場所", "示範非攻擊的解決衝突策略，作為孩子的楷模", "採用同理心訓練方式，以其人之道還治其人之身，讓孩子體會別人的痛苦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05621', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在增進兒童社交技巧的訓練中，下列那一種作法不適切？', '["好的行為要受到鼓勵，不好的行為要加以處罰", "安排社會環境提供社交機會，如透過遊戲的方式", "示範社交的合宜行為，並說明這些行為的理由，然後一起練習", "以布偶演出的角色扮演是一種認知上的策略"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05622', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '實證研究顯示，老師的期許對學生表現究竟會造成何種影響，下列陳述何者正確？', '["老師低估學生的潛能會帶給學生負面影響，學生成績降低30%", "老師對學生高期望，會帶給學生壓力，成績僅增加10%", "如果老師重視低學習成就的學生，學生的表現會更好", "學生的自我期許才是關鍵因素，老師的期許影響不大"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05623', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '父母婚姻的衝突與離婚已成為兒童發展上的障礙，針對此議題的相關研究，下列敘述何者錯誤？', '["父母離婚對兒童是一系列的痛苦經驗所串連而成", "兒童會擔憂是否失去基本的生活條件、安全保障或父母的愛", "在長期追蹤研究的預後情況，年齡稍長的兒童都比幼兒的適應情況好", "多數女孩在父母離婚後會比多數男孩適應得更好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05624', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「小爸爸」的現象逐漸被社會所關注，針對此議題的相關研究，下列敘述何者不適切？', '["有許多小爸爸不想放棄自己的孩子，想參與撫育的過程", "小爸爸有時須面對女朋友父母的敵意，當要為嬰兒做決定時，社工要將小爸爸的意見納入考量中", "社工應對小爸爸提供嬰兒照顧與營養知識的相關訓練", "性教育是對小爸爸提供服務時最重要的計畫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05625', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於失智症（dementia）的描述，下列何者不適當？', '["最初的臨床症狀表徵是記憶力減退和精神能力的降低", "多見於老年人，年齡越大越容易發生", "阿茲海默症是失智症最常見的類型", "對於複雜的生活功能開始產生障礙，這是屬於中度失智症的程度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05626', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '許多人退休後持續參與或開始投入志願服務，針對高齡志工的描述，何者不適當？', '["「退休後才參與」的志工，其參與頻率的表現上，會明顯的多於「退休前就參與」的志工", "服務過程中的團體歸屬感，以及與志工伙伴、機構人員的相處與分享，是他們參與服務的過程中重要 的支持力量", "彈性且自主安排的參與方式，有利於退休時間的規劃，亦是讓他們願意繼續參加的原因", "基於女性高齡志工長期對家庭的責任感，使得她們在保持家務為優先的前提下，即使參與社區事務也 不影響家庭的正常作息或運作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05627', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '所有的嬰兒出生後就具有基本的情緒傾向，謂之為氣質或性情，下列那一種氣質類型的小孩比例最低？', '["隨和小孩", "困難小孩", "緩慢小孩", "好動小孩"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05628', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據艾瑞克森（Erikson）提出的社會心理發展階段理論，兒童早期（約3歲至5歲）的發展任務是：', '["主動", "信任", "勤奮", "自主"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05629', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列關於中年期的描述，何者不適切？', '["和其他階段不同的是，中年期比較少受到生理變化的影響，主要受個人經驗的影響，個別的差異頗大", "必須察覺文化在建構「合宜的中年角色」之信念上所發揮的功能", "歸納推理、空間定向、字彙、語文記憶達到高峰，但知覺、速度反應有所下降", "許多中年女性是屬於一種沒有朋友的邊緣人，加上沒有支持系統，自殺率明顯高於男性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
